class FallbackManager{constructor(t){this.router=t,this.fallbackRoutes={auth:"/login","session-expired":"/login",unauthorized:"/login",forbidden:"/login","seller-required":"/seller-verification","admin-required":"/admin","buyer-required":"/dashboard","not-found":"/","server-error":"/","network-error":"/","cart-empty":"/products","checkout-error":"/cart","payment-error":"/cart",default:"/"}}getFallback(t,e=null){if(this.fallbackRoutes[t])return this.fallbackRoutes[t];if(e){if("seller"===e&&(t.includes("admin")||t.includes("seller")))return"/seller-dashboard";if("admin"===e&&t.includes("admin"))return"/admin";if("buyer"===e)return"/dashboard"}return"/"}executeFallback(t,e=null){const o=this.getFallback(t,e);console.log(`🔄 Executing fallback: ${t} → ${o}`),this.router.navigate(o,{replace:!0})}}class Router{constructor(){this.routes=new Map,this.fallbackManager=new FallbackManager(this),this.currentPath=null,this.history=[],this.maxHistory=50,this.loadingElement=null,this.init()}init(){this.loadingElement=document.createElement("div"),this.loadingElement.id="router-loading",this.loadingElement.innerHTML='<div class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"><div class="bg-white p-6 rounded-lg shadow-xl"><div class="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto"></div><p class="mt-2 text-gray-600">Loading...</p></div></div>',window.addEventListener("popstate",t=>{this.handlePopState(t)}),document.addEventListener("click",t=>{this.handleLinkClick(t)}),this.loadInitialRoute()}handlePopState(t){const e=t.state?.path||window.location.pathname;this.navigate(e,{replace:!0})}handleLinkClick(t){const e=t.target.closest("a");if(e&&e.getAttribute("href")?.startsWith("/")&&!e.getAttribute("target")){t.preventDefault();const o=e.getAttribute("href");this.navigate(o)}}async navigate(t,e={}){if(t===this.currentPath)return;const{replace:o=!1,force:n=!1}=e;if(!n&&this.history.includes(t)&&!o)return void console.log(`📍 Already at route: ${t}`);this.showLoading();try{const e=await this.loadRoute(t);if(e){this.hideLoading(),this.updateHistory(t,o),this.currentPath=t,window.scrollTo(0,0)}else this.fallbackManager.executeFallback("not-found")}catch(e){console.error("❌ Navigation error:",e),this.hideLoading(),this.fallbackManager.executeFallback("network-error")}}async loadRoute(t){const e=this.routes.get(t);if(!e)return!1;try{if("function"==typeof e)return await e();if("string"==typeof e){const o=await fetch(e);if(!o.ok)throw new Error(`Failed to load route: ${t}`);const n=await o.text();return this.renderContent(n),!0}}catch(e){return console.error(`❌ Error loading route ${t}:`,e),!1}return!1}renderContent(t){const e=document.getElementById("app");if(e)e.innerHTML=t;else{const e=document.createElement("div");e.id="app",e.innerHTML=t,document.body.appendChild(e)}this.dispatchRouteEvent()}dispatchRouteEvent(){window.dispatchEvent(new CustomEvent("routeChanged",{detail:{path:this.currentPath}}))}updateHistory(t,e){e?window.history.replaceState({path:t},"",t):window.history.pushState({path:t},"",t),this.history.unshift(t),this.history.length>this.maxHistory&&(this.history=this.history.slice(0,this.maxHistory))}showLoading(){this.loadingElement&&document.body.appendChild(this.loadingElement)}hideLoading(){this.loadingElement&&this.loadingElement.remove()}addRoute(t,e){this.routes.set(t,e)}removeRoute(t){this.routes.delete(t)}loadInitialRoute(){const t=window.location.pathname;this.navigate(t,{replace:!0})}}const router=new Router;function addRoute(t,e){router.addRoute(t,e)}function navigate(t,e){router.navigate(t,e)}function back(){window.history.back()}function forward(){window.history.forward()}window.Router=Router,window.router=router,window.addRoute=addRoute,window.navigate=navigate,window.back=back,window.forward=forward;
